// Custom debounce hook: returns a debounced copy of `value` plus a
// `pending` flag that is true while we're waiting out the delay.
function useDebouncedValue(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [pending, setPending] = useState(false);
    const timeoutRef = useRef(null);

    useEffect(() => {
        // If the value already matches, there's nothing to debounce.
        if (value === debouncedValue) {
            setPending(false);
            return;
        }

        setPending(true);
        timeoutRef.current = setTimeout(() => {
            setDebouncedValue(value);
            setPending(false);
        }, delay);

        // Cleanup clears the pending timeout on every change AND on unmount,
        // preventing stale updates / memory leaks.
        return () => {
            clearTimeout(timeoutRef.current);
        };
